    cookie: admin.cookie
  });
  assert.equal(invalidAuditTo.status, 400);
  assert.equal(invalidAuditTo.json.error.code, 'VALIDATION_ERROR');

  const auditEvents = await request({
    path: '/audit/events?page=1&pageSize=20&filter[action]=JOB_APPROVE',
    method: 'GET',
    cookie: admin.cookie
  });
