                  <summary>Printable details</summary>
                  <pre>{JSON.stringify(inboxState.printable, null, 2)}</pre>
                </details>
              ) : null}
            </article>
          </FeatureGuard>
        ) : null}

        {activeTab === 'audit' ? (
          <FeatureGuard canAccess={hasAccess('audit')} tabId="audit">
