            </article>
          </FeatureGuard>
        ) : null}

        {activeTab === 'audit' ? (
          <FeatureGuard canAccess={hasAccess('audit')} tabId="audit">
            <article className="card" key={`audit-${sessionNonce}`}>
              <h2>Audit View</h2>
