                <pre>{JSON.stringify(auditState, null, 2)}</pre>
              </details>
            </article>
          </FeatureGuard>
        ) : null}
      </section>

      <footer className="footer">Allowed tabs: {allowedTabs.map((tab) => tab.label).join(' | ') || 'none'}</footer>
    </main>
  );
}

export default App;

